var minimumSubarrayLength = function(nums, k) {
    const n = nums.length;
    let best = Infinity;
    for (let i = 0; i < n; i++) {
        let cur = 0;
        for (let j = i; j < n; j++) {
            cur |= nums[j];
            if (cur >= k) {
                best = Math.min(best, j - i + 1);
                break;
            }
        }
    }
    return best === Infinity ? -1 : best;
};
